import type { BackendListing } from '@/types/bff'

// ─── Domain types ─────────────────────────────────────────────────────────────

/** A card the user needs to buy (not owned) */
export interface MissingCard {
  catalogSku: string
  cardName: string
  quantity: number
}

/** Optimization strategy */
export type OptimizationMode = 'cheapest' | 'fewest-sellers' | 'best-value'

/** A single card assigned to a specific listing/seller */
export interface SellerAssignment {
  catalogSku: string
  cardName: string
  quantity: number
  listing: BackendListing
}

/** Group of cards assigned to the same seller */
export interface SellerGroup {
  sellerId: string
  sellerName: string
  sellerRating?: number
  sellerReviewCount?: number
  assignments: SellerAssignment[]
  subtotal: number          // cents — sum of (price * quantity) for this seller
  shippingCost: number      // cents — one-time shipping cost for this seller
  total: number             // cents — subtotal + shippingCost
}

/** Full result of the optimization algorithm */
export interface OptimizationResult {
  mode: OptimizationMode
  sellerGroups: SellerGroup[]
  totalCost: number         // cents — sum of all seller group totals
  totalShipping: number     // cents — sum of all seller shipping costs
  totalCards: number        // count of cards successfully assigned
  unassignedCards: MissingCard[]  // cards with no available listings
  totalWithoutOptimization: number  // cents — naive sum of cheapest-per-card + per-card shipping
  savings: number           // cents — totalWithoutOptimization - totalCost (>= 0)
  timestamp: number         // Date.now() when result was computed
}

// ─── BFF request/response ─────────────────────────────────────────────────────

/** POST /api/optimizer/listings request body */
export interface OptimizerListingsRequest {
  catalogSkus: string[]
}

/** POST /api/optimizer/listings response body */
export interface OptimizerListingsResponse {
  listings: Record<string, BackendListing[]>
  errors: string[]          // SKUs that failed to fetch
  timestamp: number
}

import type { BackendListing } from '@/types/bff'
import type {
  MissingCard,
  OptimizationMode,
  OptimizationResult,
  SellerAssignment,
  SellerGroup,
} from './types'

// ─── Shipping cost derivation ─────────────────────────────────────────────────

const SHIPPING_RATES: Record<string, number> = {
  standard: 399,
  tracked: 599,
}
const DEFAULT_SHIPPING = 399

/**
 * Derive shipping cost in cents from a listing.
 * Prefers explicit shippingCost, falls back to method-based flat rate.
 */
export function deriveShippingCost(
  shippingMethod: string,
  shippingCost?: number,
): number {
  if (shippingCost !== undefined && shippingCost !== null) return shippingCost
  return SHIPPING_RATES[shippingMethod] ?? DEFAULT_SHIPPING
}

function getShippingCost(listing: BackendListing): number {
  return deriveShippingCost(listing.shippingMethod, listing.shippingCost)
}

// ─── Internal types ───────────────────────────────────────────────────────────

/** Deduplicated card with listing count for scarcity sort */
interface CardWorkItem {
  catalogSku: string
  cardName: string
  quantity: number
}

/** Tracks what a seller has been assigned so far */
interface SellerAccumulator {
  sellerId: string
  sellerName: string
  sellerRating?: number
  sellerReviewCount?: number
  assignments: SellerAssignment[]
  shippingCost: number // fixed per-seller shipping (set on first assignment)
}

// ─── Pre-processing ───────────────────────────────────────────────────────────

/**
 * Deduplicate missing cards by catalogSku, summing quantities.
 */
function deduplicateCards(cards: MissingCard[]): CardWorkItem[] {
  const map = new Map<string, CardWorkItem>()
  for (const card of cards) {
    const existing = map.get(card.catalogSku)
    if (existing) {
      existing.quantity += card.quantity
    } else {
      map.set(card.catalogSku, {
        catalogSku: card.catalogSku,
        cardName: card.cardName,
        quantity: card.quantity,
      })
    }
  }
  return Array.from(map.values())
}

/**
 * Sort cards by listing scarcity (ascending), then by catalogSku for determinism.
 */
function sortByScarcity(
  cards: CardWorkItem[],
  listingsByCard: Record<string, BackendListing[]>,
): CardWorkItem[] {
  return [...cards].sort((a, b) => {
    const aCount = listingsByCard[a.catalogSku]?.length ?? 0
    const bCount = listingsByCard[b.catalogSku]?.length ?? 0
    if (aCount !== bCount) return aCount - bCount
    return a.catalogSku.localeCompare(b.catalogSku)
  })
}

// ─── Greedy assignment core ───────────────────────────────────────────────────

/**
 * Assign a card to sellers using the cheapest marginal cost strategy.
 * Handles quantity splitting when a single listing can't fulfill demand.
 */
function assignCardCheapest(
  card: CardWorkItem,
  listings: BackendListing[],
  sellers: Map<string, SellerAccumulator>,
  remainingQuantities: Map<string, number>,
): void {
  let needed = card.quantity

  while (needed > 0) {
    let bestListing: BackendListing | null = null
    let bestCost = Infinity
    let bestQty = 0

    for (const listing of listings) {
      const available = remainingQuantities.get(listing.id) ?? 0
      if (available <= 0) continue

      const qty = Math.min(needed, available)
      const isNewSeller = !sellers.has(listing.sellerId)
      const shippingIncrement = isNewSeller ? getShippingCost(listing) : 0
      const marginalCost = listing.price * qty + shippingIncrement

      if (
        marginalCost < bestCost ||
        (marginalCost === bestCost && listing.sellerId < (bestListing?.sellerId ?? ''))
      ) {
        bestListing = listing
        bestCost = marginalCost
        bestQty = qty
      }
    }

    if (!bestListing) break // no more listings available

    // Assign
    const sellerId = bestListing.sellerId
    if (!sellers.has(sellerId)) {
      sellers.set(sellerId, {
        sellerId,
        sellerName: bestListing.sellerName,
        sellerRating: bestListing.sellerRating,
        sellerReviewCount: bestListing.sellerReviewCount,
        assignments: [],
        shippingCost: getShippingCost(bestListing),
      })
    }

    sellers.get(sellerId)!.assignments.push({
      catalogSku: card.catalogSku,
      cardName: card.cardName,
      quantity: bestQty,
      listing: bestListing,
    })

    // Decrease remaining stock for this listing
    remainingQuantities.set(
      bestListing.id,
      (remainingQuantities.get(bestListing.id) ?? 0) - bestQty,
    )
    needed -= bestQty
  }
}

/**
 * Assign a card preferring sellers already in the result set.
 * Among existing sellers, pick cheapest. If none have the card, add cheapest new seller.
 */
function assignCardFewestSellers(
  card: CardWorkItem,
  listings: BackendListing[],
  sellers: Map<string, SellerAccumulator>,
  remainingQuantities: Map<string, number>,
): void {
  let needed = card.quantity

  while (needed > 0) {
    // Separate into existing vs new sellers
    let bestListing: BackendListing | null = null
    let bestCost = Infinity
    let bestQty = 0
    let foundExisting = false

    // First pass: existing sellers only
    for (const listing of listings) {
      const available = remainingQuantities.get(listing.id) ?? 0
      if (available <= 0) continue
      if (!sellers.has(listing.sellerId)) continue

      const qty = Math.min(needed, available)
      const cost = listing.price * qty // no shipping — seller already in set

      if (
        cost < bestCost ||
        (cost === bestCost && listing.sellerId < (bestListing?.sellerId ?? ''))
      ) {
        bestListing = listing
        bestCost = cost
        bestQty = qty
        foundExisting = true
      }
    }

    // Second pass: new sellers (only if no existing seller has this card)
    if (!foundExisting) {
      for (const listing of listings) {
        const available = remainingQuantities.get(listing.id) ?? 0
        if (available <= 0) continue

        const qty = Math.min(needed, available)
        const cost = listing.price * qty + getShippingCost(listing)

        if (
          cost < bestCost ||
          (cost === bestCost && listing.sellerId < (bestListing?.sellerId ?? ''))
        ) {
          bestListing = listing
          bestCost = cost
          bestQty = qty
        }
      }
    }

    if (!bestListing) break

    const sellerId = bestListing.sellerId
    if (!sellers.has(sellerId)) {
      sellers.set(sellerId, {
        sellerId,
        sellerName: bestListing.sellerName,
        sellerRating: bestListing.sellerRating,
        sellerReviewCount: bestListing.sellerReviewCount,
        assignments: [],
        shippingCost: getShippingCost(bestListing),
      })
    }

    sellers.get(sellerId)!.assignments.push({
      catalogSku: card.catalogSku,
      cardName: card.cardName,
      quantity: bestQty,
      listing: bestListing,
    })

    remainingQuantities.set(
      bestListing.id,
      (remainingQuantities.get(bestListing.id) ?? 0) - bestQty,
    )
    needed -= bestQty
  }
}

// ─── Result assembly ──────────────────────────────────────────────────────────

function buildResult(
  mode: OptimizationMode,
  sellers: Map<string, SellerAccumulator>,
  unassignedCards: MissingCard[],
  listingsByCard: Record<string, BackendListing[]>,
  allCards: CardWorkItem[],
): OptimizationResult {
  const sellerGroups: SellerGroup[] = Array.from(sellers.values())
    .map((acc) => {
      const subtotal = acc.assignments.reduce(
        (sum, a) => sum + a.listing.price * a.quantity,
        0,
      )
      return {
        sellerId: acc.sellerId,
        sellerName: acc.sellerName,
        sellerRating: acc.sellerRating,
        sellerReviewCount: acc.sellerReviewCount,
        assignments: acc.assignments,
        subtotal,
        shippingCost: acc.shippingCost,
        total: subtotal + acc.shippingCost,
      }
    })
    .sort((a, b) => a.sellerId.localeCompare(b.sellerId)) // deterministic order

  const totalCost = sellerGroups.reduce((sum, g) => sum + g.total, 0)
  const totalShipping = sellerGroups.reduce((sum, g) => sum + g.shippingCost, 0)
  const totalCards = sellerGroups.reduce(
    (sum, g) => sum + g.assignments.reduce((s, a) => s + a.quantity, 0),
    0,
  )

  // Naive cost: cheapest per-card without shipping optimization
  // Each card picks its cheapest listing, shipping charged per-card (not amortized)
  const totalWithoutOptimization = computeNaiveCost(allCards, listingsByCard)
  const savings = Math.max(0, totalWithoutOptimization - totalCost)

  return {
    mode,
    sellerGroups,
    totalCost,
    totalShipping,
    totalCards,
    unassignedCards,
    totalWithoutOptimization,
    savings,
    timestamp: Date.now(),
  }
}

/**
 * Compute naive cost: for each card, pick cheapest listing price + that listing's
 * shipping cost, treating every card as a separate purchase (no seller grouping).
 */
function computeNaiveCost(
  cards: CardWorkItem[],
  listingsByCard: Record<string, BackendListing[]>,
): number {
  let total = 0
  for (const card of cards) {
    const listings = listingsByCard[card.catalogSku]
    if (!listings || listings.length === 0) continue

    // Sort by price ascending for cheapest-first allocation
    const sorted = [...listings].sort((a, b) => a.price - b.price)
    let needed = card.quantity

    for (const listing of sorted) {
      if (needed <= 0) break
      const qty = Math.min(needed, listing.quantity)
      // Naive: each pick pays its own shipping
      total += listing.price * qty + getShippingCost(listing)
      needed -= qty
    }
  }
  return total
}

// ─── Main optimizer ───────────────────────────────────────────────────────────

/**
 * Greedy cart optimizer. Pure function — no side effects.
 *
 * Finds optimal seller combinations for missing cards across three modes:
 * - cheapest: minimize total cost (price + amortized shipping)
 * - fewest-sellers: minimize seller count, breaking ties by price
 * - best-value: run cheapest, then try consolidating if cost increase < 15%
 */
export function optimizeCart(
  missingCards: MissingCard[],
  listingsByCard: Record<string, BackendListing[]>,
  mode: OptimizationMode,
): OptimizationResult {
  // Edge case: empty input
  if (!missingCards || missingCards.length === 0) {
    return {
      mode,
      sellerGroups: [],
      totalCost: 0,
      totalShipping: 0,
      totalCards: 0,
      unassignedCards: [],
      totalWithoutOptimization: 0,
      savings: 0,
      timestamp: Date.now(),
    }
  }

  // Pre-processing: deduplicate by catalogSku
  const deduped = deduplicateCards(missingCards)

  // Separate cards with no listings
  const unassignedCards: MissingCard[] = []
  const assignableCards: CardWorkItem[] = []

  for (const card of deduped) {
    const listings = listingsByCard[card.catalogSku]
    if (!listings || listings.length === 0) {
      unassignedCards.push({
        catalogSku: card.catalogSku,
        cardName: card.cardName,
        quantity: card.quantity,
      })
    } else {
      assignableCards.push(card)
    }
  }

  // Sort by scarcity (fewest listings first)
  const sorted = sortByScarcity(assignableCards, listingsByCard)

  if (mode === 'best-value') {
    return runBestValue(sorted, listingsByCard, unassignedCards, deduped)
  }

  // Build initial remaining-quantity map across all listings
  const remainingQuantities = buildRemainingQuantities(listingsByCard)
  const sellers = new Map<string, SellerAccumulator>()

  const assignFn =
    mode === 'cheapest' ? assignCardCheapest : assignCardFewestSellers

  for (const card of sorted) {
    const listings = listingsByCard[card.catalogSku] ?? []
    assignFn(card, listings, sellers, remainingQuantities)
  }

  return buildResult(mode, sellers, unassignedCards, listingsByCard, deduped)
}

/**
 * Best-value mode: run cheapest as baseline, then run fewest-sellers.
 * If fewest-sellers cost increase is < 15%, use it. Otherwise use cheapest.
 * Weighted: 0.7 * normalizedCost + 0.3 * normalizedSellerCount.
 */
function runBestValue(
  sorted: CardWorkItem[],
  listingsByCard: Record<string, BackendListing[]>,
  unassignedCards: MissingCard[],
  allCards: CardWorkItem[],
): OptimizationResult {
  // Run cheapest
  const cheapestQuantities = buildRemainingQuantities(listingsByCard)
  const cheapestSellers = new Map<string, SellerAccumulator>()
  for (const card of sorted) {
    assignCardCheapest(
      card,
      listingsByCard[card.catalogSku] ?? [],
      cheapestSellers,
      cheapestQuantities,
    )
  }
  const cheapestResult = buildResult(
    'cheapest',
    cheapestSellers,
    unassignedCards,
    listingsByCard,
    allCards,
  )

  // Run fewest-sellers
  const fewestQuantities = buildRemainingQuantities(listingsByCard)
  const fewestSellers = new Map<string, SellerAccumulator>()
  for (const card of sorted) {
    assignCardFewestSellers(
      card,
      listingsByCard[card.catalogSku] ?? [],
      fewestSellers,
      fewestQuantities,
    )
  }
  const fewestResult = buildResult(
    'fewest-sellers',
    fewestSellers,
    unassignedCards,
    listingsByCard,
    allCards,
  )

  // If cheapest has 0 cost, just return it
  if (cheapestResult.totalCost === 0) {
    return { ...cheapestResult, mode: 'best-value' }
  }

  // Check if fewest-sellers is within 15% cost increase
  const costIncrease =
    (fewestResult.totalCost - cheapestResult.totalCost) / cheapestResult.totalCost

  if (costIncrease <= 0.15) {
    // Fewest-sellers is close enough in cost — use it for fewer sellers
    return { ...fewestResult, mode: 'best-value' }
  }

  // Use weighted scoring: 0.7 * normalizedCost + 0.3 * normalizedSellerCount
  const maxCost = Math.max(cheapestResult.totalCost, fewestResult.totalCost)
  const maxSellers = Math.max(
    cheapestResult.sellerGroups.length,
    fewestResult.sellerGroups.length,
  )

  if (maxCost === 0 || maxSellers === 0) {
    return { ...cheapestResult, mode: 'best-value' }
  }

  const cheapestScore =
    0.7 * (cheapestResult.totalCost / maxCost) +
    0.3 * (cheapestResult.sellerGroups.length / maxSellers)
  const fewestScore =
    0.7 * (fewestResult.totalCost / maxCost) +
    0.3 * (fewestResult.sellerGroups.length / maxSellers)

  const winner = cheapestScore <= fewestScore ? cheapestResult : fewestResult
  return { ...winner, mode: 'best-value' }
}

/**
 * Build a map of listing ID → remaining quantity for all listings.
 */
function buildRemainingQuantities(
  listingsByCard: Record<string, BackendListing[]>,
): Map<string, number> {
  const map = new Map<string, number>()
  for (const listings of Object.values(listingsByCard)) {
    for (const listing of listings) {
      // If same listing appears under multiple SKUs (shouldn't, but be safe),
      // use the listing's own quantity
      map.set(listing.id, listing.quantity)
    }
  }
  return map
}

// ─── Diagnostics ──────────────────────────────────────────────────────────────

/**
 * Human-readable summary for diagnostics / logging.
 */
export function formatOptimizationSummary(result: OptimizationResult): string {
  const lines: string[] = []
  lines.push(
    `[cart-optimizer] Mode: ${result.mode} | ` +
      `${result.totalCards} cards from ${result.sellerGroups.length} seller(s) | ` +
      `Total: $${(result.totalCost / 100).toFixed(2)} ` +
      `(shipping: $${(result.totalShipping / 100).toFixed(2)}) | ` +
      `Savings: $${(result.savings / 100).toFixed(2)}`,
  )

  if (result.unassignedCards.length > 0) {
    lines.push(
      `[cart-optimizer] ${result.unassignedCards.length} card(s) unavailable: ` +
        result.unassignedCards.map((c) => c.cardName).join(', '),
    )
  }

  for (const group of result.sellerGroups) {
    lines.push(
      `  ${group.sellerName} (${group.assignments.length} cards): ` +
        `$${(group.subtotal / 100).toFixed(2)} + ` +
        `$${(group.shippingCost / 100).toFixed(2)} ship = ` +
        `$${(group.total / 100).toFixed(2)}`,
    )
  }

  return lines.join('\n')
}

"use client"

import * as React from "react"
import * as SheetPrimitive from "@radix-ui/react-dialog"
import { cva, type VariantProps } from "class-variance-authority"
import { X } from "lucide-react"

import { cn } from "@/lib/utils"

const Sheet = SheetPrimitive.Root

const SheetTrigger = SheetPrimitive.Trigger

const SheetClose = SheetPrimitive.Close

const SheetPortal = SheetPrimitive.Portal

const SheetOverlay = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Overlay>,
  React.ComponentPropsWithoutRef<typeof SheetPrimitive.Overlay>
>(({ className, ...props }, ref) => (
  <SheetPrimitive.Overlay
    className={cn(
      "fixed inset-0 z-50 bg-black/80  data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0",
      className
    )}
    {...props}
    ref={ref}
  />
))
SheetOverlay.displayName = SheetPrimitive.Overlay.displayName

const sheetVariants = cva(
  "fixed z-50 gap-4 bg-background p-6 shadow-lg transition ease-in-out data-[state=closed]:duration-300 data-[state=open]:duration-500 data-[state=open]:animate-in data-[state=closed]:animate-out",
  {
    variants: {
      side: {
        top: "inset-x-0 top-0 border-b data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top",
        bottom:
          "inset-x-0 bottom-0 border-t data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom",
        left: "inset-y-0 left-0 h-full w-3/4 border-r data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left sm:max-w-sm",
        right:
          "inset-y-0 right-0 h-full w-3/4 border-l data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right sm:max-w-sm",
      },
    },
    defaultVariants: {
      side: "right",
    },
  }
)

interface SheetContentProps
  extends React.ComponentPropsWithoutRef<typeof SheetPrimitive.Content>,
    VariantProps<typeof sheetVariants> {}

const SheetContent = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Content>,
  SheetContentProps
>(({ side = "right", className, children, ...props }, ref) => (
  <SheetPortal>
    <SheetOverlay />
    <SheetPrimitive.Content
      ref={ref}
      className={cn(sheetVariants({ side }), className)}
      {...props}
    >
      <SheetPrimitive.Close className="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background transition-opacity hover:opacity-100 focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none data-[state=open]:bg-secondary">
        <X className="h-4 w-4" />
        <span className="sr-only">Close</span>
      </SheetPrimitive.Close>
      {children}
    </SheetPrimitive.Content>
  </SheetPortal>
))
SheetContent.displayName = SheetPrimitive.Content.displayName

const SheetHeader = ({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) => (
  <div
    className={cn(
      "flex flex-col space-y-2 text-center sm:text-left",
      className
    )}
    {...props}
  />
)
SheetHeader.displayName = "SheetHeader"

const SheetFooter = ({
  className,
  ...props
}: React.HTMLAttributes<HTMLDivElement>) => (
  <div
    className={cn(
      "flex flex-col-reverse sm:flex-row sm:justify-end sm:space-x-2",
      className
    )}
    {...props}
  />
)
SheetFooter.displayName = "SheetFooter"

const SheetTitle = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Title>,
  React.ComponentPropsWithoutRef<typeof SheetPrimitive.Title>
>(({ className, ...props }, ref) => (
  <SheetPrimitive.Title
    ref={ref}
    className={cn("text-lg font-semibold text-foreground", className)}
    {...props}
  />
))
SheetTitle.displayName = SheetPrimitive.Title.displayName

const SheetDescription = React.forwardRef<
  React.ElementRef<typeof SheetPrimitive.Description>,
  React.ComponentPropsWithoutRef<typeof SheetPrimitive.Description>
>(({ className, ...props }, ref) => (
  <SheetPrimitive.Description
    ref={ref}
    className={cn("text-sm text-muted-foreground", className)}
    {...props}
  />
))
SheetDescription.displayName = SheetPrimitive.Description.displayName

export {
  Sheet,
  SheetPortal,
  SheetOverlay,
  SheetTrigger,
  SheetClose,
  SheetContent,
  SheetHeader,
  SheetFooter,
  SheetTitle,
  SheetDescription,
}

"use client"

import { useState } from "react"
import Link from "next/link"
import { useCustomer } from "@/hooks/useCustomer"
import {
  Heart,
  Copy,
  Share2,
  Edit,
  Download,
  ArrowLeft,
  Globe,
  Lock,
  ShoppingCart,
  User,
  Check,
} from "lucide-react"

interface Props {
  deck: any
  onLike?: () => void
  onCopy?: () => void
  onShare?: () => void
  liked?: boolean
  likeCount?: number
}

export function DeckViewerHeader({
  deck,
  onLike,
  onCopy,
  onShare,
  liked = false,
  likeCount = 0,
}: Props) {
  const { customer, isAuthenticated } = useCustomer()
  const isOwner = isAuthenticated && customer && deck.userId === customer.id

  const formatDate = (date: string | Date) => {
    const d = new Date(date)
    const now = new Date()
    const diff = now.getTime() - d.getTime()
    const days = Math.floor(diff / (1000 * 60 * 60 * 24))
    if (days === 0) return "Today"
    if (days === 1) return "1 day ago"
    if (days < 30) return `${days} days ago`
    return d.toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    })
  }

  const totalCards = deck.stats?.totalCards || 0
  const totalValue = deck.pricing?.totalValue

  return (
    <div data-testid="deck-viewer-header" className="relative overflow-hidden">
      {/* Gradient background */}
      <div
        className="absolute inset-0"
        style={{
          background: `
            linear-gradient(135deg, rgba(167, 139, 250, 0.12) 0%, rgba(139, 92, 246, 0.04) 40%, transparent 70%),
            linear-gradient(to bottom, transparent 60%, var(--bg-base, #09090F) 100%)
          `,
        }}
      />
      <div
        className="absolute -top-20 -right-20 w-[400px] h-[400px]"
        style={{
          background:
            "radial-gradient(circle, rgba(167, 139, 250, 0.08) 0%, transparent 70%)",
        }}
      />

      <div className="relative z-[1] px-6 md:px-12 pt-6 md:pt-12 pb-8 md:pb-12">
        {/* Back link */}
        <Link
          href="/decks"
          className="inline-flex items-center gap-2 mb-6 text-sm transition-colors hover:opacity-80"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
