"use client"

import React, { createContext, useContext, useState, useCallback } from 'react'
import { cn } from '@/lib/utils'

interface Toast {
  id: string
  type: 'success' | 'error' | 'warning' | 'info'
  title: string
  description?: string
  duration?: number
  action?: {
    label: string
    onClick: () => void
  }
}

interface ToastContextType {
  toasts: Toast[]
  addToast: (toast: Omit<Toast, 'id'>) => void
  removeToast: (id: string) => void
  success: (title: string, description?: string, action?: Toast['action']) => void
  error: (title: string, description?: string, action?: Toast['action']) => void
  warning: (title: string, description?: string, action?: Toast['action']) => void
  info: (title: string, description?: string, action?: Toast['action']) => void
}

const ToastContext = createContext<ToastContextType | undefined>(undefined)

export function useToast() {
  const context = useContext(ToastContext)
  if (!context) {
    throw new Error('useToast must be used within a ToastProvider')
  }
  return context
}

const generateId = () => Math.random().toString(36).substr(2, 9)

export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([])

  const removeToast = useCallback((id: string) => {
    setToasts(prev => prev.filter(toast => toast.id !== id))
  }, [])

  const addToast = useCallback((toast: Omit<Toast, 'id'>) => {
    const id = generateId()
    const newToast = { ...toast, id }
    
    setToasts(prev => [...prev, newToast])
    
    // Auto remove after duration (default 5 seconds)
    const duration = toast.duration ?? (toast.type === 'error' ? 8000 : 5000)
    if (duration > 0) {
      setTimeout(() => {
        removeToast(id)
      }, duration)
    }
    
    return id
  }, [removeToast])

  const success = useCallback((title: string, description?: string, action?: Toast['action']) => {
    addToast({ type: 'success', title, description, action })
  }, [addToast])

  const error = useCallback((title: string, description?: string, action?: Toast['action']) => {
    addToast({ type: 'error', title, description, action })
  }, [addToast])

  const warning = useCallback((title: string, description?: string, action?: Toast['action']) => {
    addToast({ type: 'warning', title, description, action })
  }, [addToast])

  const info = useCallback((title: string, description?: string, action?: Toast['action']) => {
    addToast({ type: 'info', title, description, action })
  }, [addToast])

  const value: ToastContextType = {
    toasts,
    addToast,
    removeToast,
    success,
    error,
    warning,
    info
  }

  return (
    <ToastContext.Provider value={value}>
      {children}
      <ToastContainer />
    </ToastContext.Provider>
  )
}

function ToastContainer() {
  const { toasts, removeToast } = useToast()

  if (toasts.length === 0) return null

  return (
    <div className="fixed top-4 right-4 z-[100] space-y-2 max-w-sm">
      {toasts.map(toast => (
        <ToastItem key={toast.id} toast={toast} onRemove={removeToast} />
      ))}
    </div>
  )
}

function ToastItem({ toast, onRemove }: { toast: Toast; onRemove: (id: string) => void }) {
  const getToastStyles = (type: Toast['type']) => {
    switch (type) {
      case 'success':
        return {
          bg: 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800',
          icon: '✅',
          iconBg: 'bg-green-100 dark:bg-green-900/40 text-green-600 dark:text-green-400'
        }
      case 'error':
        return {
          bg: 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800',
          icon: '❌',
          iconBg: 'bg-red-100 dark:bg-red-900/40 text-red-600 dark:text-red-400'
        }
      case 'warning':
        return {
          bg: 'bg-yellow-50 dark:bg-yellow-900/20 border-yellow-200 dark:border-yellow-800',
          icon: '⚠️',
          iconBg: 'bg-yellow-100 dark:bg-yellow-900/40 text-yellow-600 dark:text-yellow-400'
        }
      case 'info':
      default:
        return {
          bg: 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800',
          icon: 'ℹ️',
          iconBg: 'bg-blue-100 dark:bg-blue-900/40 text-blue-600 dark:text-blue-400'
        }
    }
  }

  const styles = getToastStyles(toast.type)

  return (
    <div className={cn(
      "relative rounded-lg border p-4 shadow-lg animate-in slide-in-from-right-full transition-all duration-300",
      styles.bg
    )}>
      <div className="flex items-start gap-3">
        <div className={cn("w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0", styles.iconBg)}>
          <span className="text-sm">{styles.icon}</span>
        </div>
        
        <div className="flex-1 min-w-0">
          <h4 className="text-sm font-medium text-primary mb-1">{toast.title}</h4>
          {toast.description && (
            <p className="text-sm text-secondary">{toast.description}</p>
          )}
          {toast.action && (
            <button
              onClick={toast.action.onClick}
              className="mt-2 text-sm font-medium text-action hover:text-action-hover underline"
            >
              {toast.action.label}
            </button>
          )}
        </div>

        <button
          onClick={() => onRemove(toast.id)}
          className="flex-shrink-0 text-secondary hover:text-primary transition-colors ml-2"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>
    </div>
  )
}

