// ─── Config ───────────────────────────────────────────────────────────────────

const BACKEND_STORE_URL =
  process.env.MEDUSA_BACKEND_URL ??
  process.env.NEXT_PUBLIC_MEDUSA_BACKEND_URL ??
  'http://localhost:9001'

const CUSTOMER_BACKEND_URL =
  process.env.CUSTOMER_BACKEND_URL ??
  process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL ??
  'http://localhost:7000'

const CONCURRENCY_LIMIT = 5
const LISTING_TIMEOUT_MS = 3000

// ─── Types ────────────────────────────────────────────────────────────────────

interface RawListing {
  id: string
  catalog_sku: string
  condition: 'NM' | 'LP' | 'MP' | 'HP' | 'DMG'
  language: string
  finish: string
  price: number
  currency: string
  quantity: number
  shipping_method: string
  seller_id: string
  seller_name: string
  seller_type: 'consumer' | 'business'
  shipping_cost?: number
  shipping_location?: string
}

interface TrustData {
  rating: number
  reviewCount: number
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

async function fetchListingsForSku(
  catalogSku: string
): Promise<{ sku: string; listings: RawListing[]; error?: string }> {
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), LISTING_TIMEOUT_MS)

  try {
    const encodedSku = encodeURIComponent(catalogSku)
    const response = await fetch(
      `${BACKEND_STORE_URL}/store/cards/listings?catalog_sku=${encodedSku}`,
      { signal: controller.signal }
    )

    if (!response.ok) {
      console.error(`[cart-optimizer] Listing fetch failed for SKU: ${catalogSku} (HTTP ${response.status})`)
      return { sku: catalogSku, listings: [], error: catalogSku }
    }

    const body = await response.json()
    return { sku: catalogSku, listings: (body.data as RawListing[]) ?? [] }
  } catch (err) {
    console.error(`[cart-optimizer] Listing fetch failed for SKU: ${catalogSku}`, err)
    return { sku: catalogSku, listings: [], error: catalogSku }
  } finally {
    clearTimeout(timeout)
  }
}

async function fetchTrustBatch(
  sellerIds: string[]
): Promise<Record<string, TrustData>> {
  if (sellerIds.length === 0) return {}

  try {
    const response = await fetch(
      `${CUSTOMER_BACKEND_URL}/api/sellers/trust/batch`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sellerIds }),
      }
    )

    if (!response.ok) {
      console.error(`[cart-optimizer] Trust batch fetch failed (HTTP ${response.status})`)
      return {}
    }

    const body = await response.json()
    return (body.data as Record<string, TrustData>) ?? {}
  } catch (err) {
    console.error('[cart-optimizer] Trust batch fetch failed', err)
    return {}
  }
}

function mergeListingsWithTrust(
  rawListings: RawListing[],
  trust: Record<string, TrustData>
): BackendListing[] {
  return rawListings.map((raw) => {
    const trustData = trust[raw.seller_id]
    const listing: BackendListing = {
      id: raw.id,
      catalogSku: raw.catalog_sku,
      condition: raw.condition,
      language: raw.language,
      finish: raw.finish,
      price: raw.price,
      currency: raw.currency,
      quantity: raw.quantity,
      shippingMethod: raw.shipping_method,
      sellerId: raw.seller_id,
      sellerName: raw.seller_name,
      sellerType: raw.seller_type,
    }

    if (raw.shipping_cost !== undefined) {
      listing.shippingCost = raw.shipping_cost
    }
    if (raw.shipping_location !== undefined) {
      listing.shippingLocation = raw.shipping_location
    }
    if (trustData) {
      listing.sellerRating = trustData.rating
      listing.sellerReviewCount = trustData.reviewCount
    }

    return listing
  })
}

/** Process SKUs in batches of CONCURRENCY_LIMIT */
async function fetchListingsInBatches(skus: string[]) {
  const results: { sku: string; listings: RawListing[]; error?: string }[] = []

  for (let i = 0; i < skus.length; i += CONCURRENCY_LIMIT) {
    const batch = skus.slice(i, i + CONCURRENCY_LIMIT)
    const batchResults = await Promise.all(
      batch.map((sku) => fetchListingsForSku(sku))
    )
    results.push(...batchResults)
  }

  return results
}

// ─── Route handler ────────────────────────────────────────────────────────────

export async function POST(request: NextRequest) {
  // Parse and validate request body
  let body: OptimizerListingsRequest
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Invalid JSON body' },
      { status: 400 }
    )
  }

  if (!body.catalogSkus || !Array.isArray(body.catalogSkus)) {
    return NextResponse.json(
      { error: 'catalogSkus must be an array of strings' },
      { status: 400 }
    )
  }

  if (body.catalogSkus.length === 0) {
    return NextResponse.json(
      { error: 'catalogSkus must not be empty' },
      { status: 400 }
    )
  }

  if (body.catalogSkus.length > 100) {
    return NextResponse.json(
      { error: 'catalogSkus must not exceed 100 items' },
      { status: 400 }
    )
  }

  // Validate all items are strings
  if (!body.catalogSkus.every((sku) => typeof sku === 'string')) {
    return NextResponse.json(
      { error: 'catalogSkus must be an array of strings' },
      { status: 400 }
    )
  }

  // Deduplicate input SKUs
  const uniqueSkus = [...new Set(body.catalogSkus)]

  // Fetch listings in batches
  const results = await fetchListingsInBatches(uniqueSkus)

  // Collect all raw listings grouped by SKU
  const rawListingsBySku: Record<string, RawListing[]> = {}
  const errors: string[] = []

  for (const result of results) {
    if (result.error) {
      errors.push(result.error)
    }
    if (result.listings.length > 0) {
      rawListingsBySku[result.sku] = result.listings
    }
  }

  // Collect all unique seller IDs across all listings
  const allSellerIds = new Set<string>()
  for (const listings of Object.values(rawListingsBySku)) {
    for (const listing of listings) {
      allSellerIds.add(listing.seller_id)
    }
  }

  // Fetch trust data in one batch call
  const trust = await fetchTrustBatch([...allSellerIds])

  // Merge listings with trust data
  const listings: Record<string, BackendListing[]> = {}
  for (const [sku, rawListings] of Object.entries(rawListingsBySku)) {
    listings[sku] = mergeListingsWithTrust(rawListings, trust)
  }

  const response: OptimizerListingsResponse = {
    listings,
    errors,
    timestamp: Date.now(),
  }

  return NextResponse.json(response)
}

