"use client"

import React, { useState } from "react"
import { ChevronDown, Star, ArrowLeftRight } from "lucide-react"
import type { SellerGroup, SellerAssignment } from "@/lib/optimizer/types"
import type { BackendListing } from "@/types/bff"

// ─── Condition badge styles (mirroring AlgoliaCardHit pattern) ────────────────

const CONDITION_STYLES: Record<string, { bg: string; color: string }> = {
  NM: { bg: "rgba(16, 185, 129, 0.12)", color: "var(--positive, #10B981)" },
  LP: { bg: "rgba(245, 158, 11, 0.12)", color: "var(--warning, #F59E0B)" },
  MP: { bg: "rgba(255, 120, 73, 0.12)", color: "var(--brand-secondary, #FF7849)" },
  HP: { bg: "rgba(239, 68, 68, 0.12)", color: "var(--negative, #EF4444)" },
  DMG: { bg: "rgba(255, 120, 73, 0.12)", color: "var(--brand-secondary, #FF7849)" },
}

// ─── Types ────────────────────────────────────────────────────────────────────

interface SellerGroupCardProps {
  group: SellerGroup
  /** All listings indexed by catalogSku — used for swap alternatives */
  listingsByCard: Record<string, BackendListing[]>
  onOverride: (catalogSku: string, newListingId: string) => void
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

function formatCents(cents: number): string {
  return `$${(cents / 100).toFixed(2)}`
}

function renderStars(rating?: number) {
  if (rating === undefined || rating === null) return null
  // Rating is 0–100 scale, convert to 0–5
  const stars = Math.round(rating / 20)
  return (
    <span className="flex items-center gap-0.5">
      {Array.from({ length: 5 }, (_, i) => (
        <Star
          key={i}
          style={{
            width: 12,
            height: 12,
            fill: i < stars ? "var(--warning, #F59E0B)" : "transparent",
            color: i < stars ? "var(--warning, #F59E0B)" : "var(--text-tertiary, #7B72A8)",
          }}
        />
      ))}
    </span>
  )
}

// ─── Component ────────────────────────────────────────────────────────────────

export function SellerGroupCard({ group, listingsByCard, onOverride }: SellerGroupCardProps) {
  const [swapOpenForSku, setSwapOpenForSku] = useState<string | null>(null)

  return (
    <div
      data-testid={`seller-group-${group.sellerId}`}
      className="rounded-lg overflow-hidden"
      style={{
        background: "var(--bg-surface-2, #21203A)",
        border: "1px solid var(--border-stroke, var(--border-default, #2C2A4A))",
      }}
    >
      {/* Seller header */}
      <div
        className="flex items-center justify-between px-4 py-3"
        style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)" }}
      >
        <div className="flex items-center gap-2">
          <span
            className="font-semibold text-sm"
            style={{ color: "var(--text-primary, #F0EEFF)" }}
          >
            {group.sellerName}
          </span>
          {renderStars(group.sellerRating)}
          {group.sellerReviewCount !== undefined && group.sellerReviewCount > 0 && (
            <span
              className="text-xs"
              style={{ color: "var(--text-tertiary, #7B72A8)" }}
            >
              ({group.sellerReviewCount})
            </span>
          )}
        </div>
        <span
          className="text-xs font-medium"
          style={{ color: "var(--text-secondary, #B8B0D8)" }}
        >
          {group.assignments.length} card{group.assignments.length !== 1 ? "s" : ""}
        </span>
      </div>

      {/* Card rows */}
      <div className="divide-y" style={{ borderColor: "var(--border-default, #2C2A4A)" }}>
        {group.assignments.map((assignment) => (
          <CardRow
            key={`${assignment.catalogSku}-${assignment.listing.id}`}
            assignment={assignment}
            alternatives={listingsByCard[assignment.catalogSku]?.filter(
              (l) => l.sellerId !== group.sellerId
            ) ?? []}
            swapOpen={swapOpenForSku === assignment.catalogSku}
            onToggleSwap={() =>
              setSwapOpenForSku((prev) =>
                prev === assignment.catalogSku ? null : assignment.catalogSku
              )
            }
            onSelectAlternative={(listingId) => {
              onOverride(assignment.catalogSku, listingId)
              setSwapOpenForSku(null)
            }}
          />
        ))}
      </div>

      {/* Footer: subtotal + shipping */}
      <div
        className="flex items-center justify-between px-4 py-3"
        style={{ borderTop: "1px solid var(--border-default, #2C2A4A)" }}
      >
        <div className="flex gap-4 text-xs" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
          <span>Subtotal: {formatCents(group.subtotal)}</span>
          <span>Shipping: {formatCents(group.shippingCost)}</span>
        </div>
        <span
          className="font-semibold text-sm"
          style={{ color: "var(--text-primary, #F0EEFF)" }}
        >
          {formatCents(group.total)}
        </span>
      </div>
    </div>
  )
}

// ─── Card Row ─────────────────────────────────────────────────────────────────

interface CardRowProps {
  assignment: SellerAssignment
  alternatives: BackendListing[]
  swapOpen: boolean
  onToggleSwap: () => void
  onSelectAlternative: (listingId: string) => void
}

function CardRow({
  assignment,
  alternatives,
  swapOpen,
  onToggleSwap,
  onSelectAlternative,
}: CardRowProps) {
  const conditionStyle = CONDITION_STYLES[assignment.listing.condition] ?? null
  const unitPrice = assignment.listing.price
  const lineTotal = unitPrice * assignment.quantity

  return (
    <div className="px-4 py-2.5">
      <div className="flex items-center justify-between gap-2">
        {/* Card info */}
        <div className="flex items-center gap-2 flex-1 min-w-0">
          <span
            className="text-sm truncate"
            style={{ color: "var(--text-primary, #F0EEFF)" }}
          >
            {assignment.cardName}
          </span>
          {assignment.quantity > 1 && (
            <span
              className="text-xs flex-shrink-0"
              style={{ color: "var(--text-tertiary, #7B72A8)" }}
            >
              ×{assignment.quantity}
            </span>
          )}
          {conditionStyle && (
            <span
              className="text-xs font-medium px-1.5 py-0.5 rounded flex-shrink-0"
              style={{
                background: conditionStyle.bg,
                color: conditionStyle.color,
              }}
            >
              {assignment.listing.condition}
            </span>
          )}
        </div>

        {/* Price + swap button */}
        <div className="flex items-center gap-2 flex-shrink-0">
          <span
            className="text-sm font-medium"
            style={{ color: "var(--text-primary, #F0EEFF)" }}
          >
            {formatCents(lineTotal)}
          </span>
          {alternatives.length > 0 && (
            <button
              onClick={onToggleSwap}
              data-testid={`swap-${assignment.catalogSku}`}
              className="flex items-center gap-1 px-2 py-1 rounded text-xs transition-colors cursor-pointer"
              style={{
                background: swapOpen
                  ? "rgba(139, 92, 246, 0.15)"
                  : "transparent",
                color: "var(--text-secondary, #B8B0D8)",
                border: `1px solid ${swapOpen ? "rgba(139, 92, 246, 0.3)" : "var(--border-default, #2C2A4A)"}`,
              }}
            >
              <ArrowLeftRight style={{ width: 12, height: 12 }} />
              <ChevronDown
                style={{
                  width: 10,
                  height: 10,
                  transform: swapOpen ? "rotate(180deg)" : undefined,
                  transition: "transform 200ms",
                }}
              />
            </button>
          )}
        </div>
      </div>

      {/* Swap dropdown */}
      {swapOpen && alternatives.length > 0 && (
        <div
          className="mt-2 rounded-md overflow-hidden"
          data-testid={`swap-options-${assignment.catalogSku}`}
          style={{
            background: "var(--bg-surface-1, #18162A)",
            border: "1px solid var(--border-default, #2C2A4A)",
          }}
        >
          {alternatives.map((alt) => {
            const altStyle = CONDITION_STYLES[alt.condition] ?? null
            return (
              <button
                key={alt.id}
                onClick={() => onSelectAlternative(alt.id)}
                className="w-full flex items-center justify-between px-3 py-2 text-xs transition-colors cursor-pointer"
                style={{
                  background: "transparent",
                  color: "var(--text-secondary, #B8B0D8)",
                  border: "none",
                  borderBottom: "1px solid var(--border-default, #2C2A4A)",
                }}
              >
                <span className="flex items-center gap-2">
                  <span style={{ color: "var(--text-primary, #F0EEFF)" }}>
                    {alt.sellerName}
                  </span>
                  {altStyle && (
                    <span
                      className="font-medium px-1 py-0.5 rounded"
                      style={{ background: altStyle.bg, color: altStyle.color }}
                    >
                      {alt.condition}
                    </span>
                  )}
                </span>
                <span style={{ color: "var(--text-primary, #F0EEFF)" }}>
                  {formatCents(alt.price)}
                </span>
              </button>
            )
          })}
        </div>
      )}
    </div>
  )
}

"use client"

import React, { useState, useEffect, useCallback, useRef } from "react"
import { ShoppingCart, RefreshCw, AlertTriangle, Loader2 } from "lucide-react"
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet"
import { OptimizerModeToggle } from "./OptimizerModeToggle"
import { SellerGroupCard } from "./SellerGroupCard"
import { optimizeCart } from "@/lib/optimizer/optimizeCart"
import { addToCart } from "@/lib/data/cart"
import { useToast } from "@/components/feedback/ToastProvider"
import type {
  MissingCard,
  OptimizationMode,
  OptimizationResult,
  OptimizerListingsResponse,
} from "@/lib/optimizer/types"
import type { BackendListing } from "@/types/bff"

// ─── Constants ────────────────────────────────────────────────────────────────

const STALENESS_THRESHOLD_MS = 5 * 60 * 1000 // 5 minutes
const MEDUSA_BACKEND_URL =
  typeof window !== "undefined"
    ? (process.env.NEXT_PUBLIC_MEDUSA_BACKEND_URL ?? "")
    : ""

// ─── Types ────────────────────────────────────────────────────────────────────

interface CartOptimizerPanelProps {
  missingCards: MissingCard[]
  open: boolean
  onClose: () => void
  /** Country code for cart operations (defaults to "us") */
  countryCode?: string
}

interface OverrideMap {
  [catalogSku: string]: string // catalogSku → listingId
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

function formatCents(cents: number): string {
  return `$${(cents / 100).toFixed(2)}`
}

function getMinutesSince(timestamp: number): number {
  return Math.floor((Date.now() - timestamp) / 60000)
}

/**
 * Apply overrides to the optimization result.
 * When a user swaps a card to a different seller's listing, we rebuild
 * the result with the override applied, then re-run the optimizer on
 * the non-overridden cards.
 */
function applyOverrides(
  missingCards: MissingCard[],
  listingsByCard: Record<string, BackendListing[]>,
  mode: OptimizationMode,
  overrides: OverrideMap,
): OptimizationResult {
  if (Object.keys(overrides).length === 0) {
    return optimizeCart(missingCards, listingsByCard, mode)
  }

  // For overridden cards, pin them to the chosen listing.
  // For non-overridden cards, let the optimizer decide.
  // Simple approach: run optimizer, then swap overridden assignments.
  const result = optimizeCart(missingCards, listingsByCard, mode)

  // Build a modified result with overrides
  for (const [sku, listingId] of Object.entries(overrides)) {
    // Find the listing in listingsByCard
    const listings = listingsByCard[sku]
    if (!listings) continue
    const targetListing = listings.find((l) => l.id === listingId)
    if (!targetListing) continue

    // Remove this card from its current seller group
    for (const group of result.sellerGroups) {
      const idx = group.assignments.findIndex((a) => a.catalogSku === sku)
      if (idx >= 0) {
        const assignment = group.assignments[idx]
        group.assignments.splice(idx, 1)
        // Update group totals
        group.subtotal -= assignment.listing.price * assignment.quantity
        group.total = group.subtotal + group.shippingCost

        // Find or create the target seller group
        let targetGroup = result.sellerGroups.find(
          (g) => g.sellerId === targetListing.sellerId
        )
        if (!targetGroup) {
          const shippingCost = targetListing.shippingCost ?? 399
          targetGroup = {
            sellerId: targetListing.sellerId,
            sellerName: targetListing.sellerName,
            sellerRating: targetListing.sellerRating,
            sellerReviewCount: targetListing.sellerReviewCount,
            assignments: [],
            subtotal: 0,
            shippingCost,
            total: shippingCost,
          }
          result.sellerGroups.push(targetGroup)
        }

        // Add assignment to target group
        targetGroup.assignments.push({
          ...assignment,
          listing: targetListing,
        })
        targetGroup.subtotal += targetListing.price * assignment.quantity
        targetGroup.total = targetGroup.subtotal + targetGroup.shippingCost
        break
      }
    }
  }

  // Remove empty seller groups
  result.sellerGroups = result.sellerGroups.filter(
    (g) => g.assignments.length > 0
  )

  // Recalculate totals
  result.totalCost = result.sellerGroups.reduce((sum, g) => sum + g.total, 0)
  result.totalShipping = result.sellerGroups.reduce(
    (sum, g) => sum + g.shippingCost,
    0,
  )
  result.totalCards = result.sellerGroups.reduce(
    (sum, g) => sum + g.assignments.reduce((s, a) => s + a.quantity, 0),
    0,
  )
  result.savings = Math.max(0, result.totalWithoutOptimization - result.totalCost)

  return result
}

// ─── Component ────────────────────────────────────────────────────────────────

export function CartOptimizerPanel({
  missingCards,
  open,
  onClose,
  countryCode = "us",
}: CartOptimizerPanelProps) {
  const toast = useToast()

  const [mode, setMode] = useState<OptimizationMode>("best-value")
  const [loading, setLoading] = useState(false)
  const [addingToCart, setAddingToCart] = useState(false)
  const [listingsByCard, setListingsByCard] = useState<Record<string, BackendListing[]>>({})
  const [fetchErrors, setFetchErrors] = useState<string[]>([])
  const [fetchTimestamp, setFetchTimestamp] = useState<number>(0)
  const [result, setResult] = useState<OptimizationResult | null>(null)
  const [overrides, setOverrides] = useState<OverrideMap>({})
  const [isStale, setIsStale] = useState(false)
  const stalenessTimerRef = useRef<NodeJS.Timeout | null>(null)

  // Fetch listings when panel opens
  const fetchListings = useCallback(async () => {
    if (missingCards.length === 0) return

    setLoading(true)
    setOverrides({})

    try {
      const uniqueSkus = [...new Set(missingCards.map((c) => c.catalogSku))]
      const response = await fetch("/api/optimizer/listings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ catalogSkus: uniqueSkus }),
      })

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}`)
      }

      const data: OptimizerListingsResponse = await response.json()
      setListingsByCard(data.listings)
      setFetchErrors(data.errors)
      setFetchTimestamp(data.timestamp)
      setIsStale(false)

      // Run optimizer
      const optimized = optimizeCart(missingCards, data.listings, mode)
      setResult(optimized)
    } catch (err) {
      console.error("[cart-optimizer] Listings fetch failed:", err)
      toast.error("Couldn't load card listings", "Please try again")
    } finally {
      setLoading(false)
    }
  }, [missingCards, mode, toast])

  // Fetch on open
  useEffect(() => {
    if (open) {
      fetchListings()
    } else {
      // Reset state when closing
      setResult(null)
      setOverrides({})
      setIsStale(false)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open])

  // Staleness timer
  useEffect(() => {
    if (stalenessTimerRef.current) {
      clearTimeout(stalenessTimerRef.current)
    }

    if (fetchTimestamp > 0 && open) {
      const elapsed = Date.now() - fetchTimestamp
      const remaining = STALENESS_THRESHOLD_MS - elapsed

      if (remaining <= 0) {
        setIsStale(true)
        console.warn("[cart-optimizer] Results stale, timestamp:", fetchTimestamp)
      } else {
        stalenessTimerRef.current = setTimeout(() => {
          setIsStale(true)
          console.warn("[cart-optimizer] Results stale, timestamp:", fetchTimestamp)
        }, remaining)
      }
    }

    return () => {
      if (stalenessTimerRef.current) {
        clearTimeout(stalenessTimerRef.current)
      }
    }
  }, [fetchTimestamp, open])

  // Mode change → re-run optimizer client-side (no re-fetch)
  const handleModeChange = useCallback(
    (newMode: OptimizationMode) => {
      setMode(newMode)
      if (Object.keys(listingsByCard).length > 0) {
        const optimized = applyOverrides(missingCards, listingsByCard, newMode, overrides)
        setResult(optimized)
      }
    },
    [listingsByCard, missingCards, overrides],
  )

  // Per-card override
  const handleOverride = useCallback(
    (catalogSku: string, newListingId: string) => {
      const newOverrides = { ...overrides, [catalogSku]: newListingId }
      setOverrides(newOverrides)

      if (Object.keys(listingsByCard).length > 0) {
        const optimized = applyOverrides(missingCards, listingsByCard, mode, newOverrides)
        setResult(optimized)
      }
    },
    [overrides, listingsByCard, missingCards, mode],
  )

  // Refresh listings
  const handleRefresh = useCallback(() => {
    fetchListings()
  }, [fetchListings])

  // Add to cart
  const handleAddToCart = useCallback(async () => {
    if (!result || result.sellerGroups.length === 0) return

    setAddingToCart(true)
    const successes: string[] = []
    const failures: { cardName: string; sellerName: string }[] = []

    // Collect all assignments to add
    const allAssignments = result.sellerGroups.flatMap((g) =>
      g.assignments.map((a) => ({ ...a, sellerName: g.sellerName }))
    )

    // Sequential add-to-cart: resolve variant ID via Medusa, then add
    for (const assignment of allAssignments) {
      try {
        // Resolve catalogSku → Medusa variant
        const response = await fetch(
          `${MEDUSA_BACKEND_URL}/store/products?catalog_sku=${encodeURIComponent(assignment.catalogSku)}`
        )

        if (!response.ok) {
          throw new Error(`Product lookup failed (HTTP ${response.status})`)
        }

        const { products } = await response.json()
        const variant = products?.[0]?.variants?.[0]

        if (!variant) {
          throw new Error("No variant found for catalogSku")
        }

        await addToCart({
          variantId: variant.id,
          quantity: assignment.quantity,
          countryCode,
        })

        successes.push(assignment.cardName)
      } catch (err) {
        console.error(
          "[cart-optimizer] Add to cart failed for variant:",
          assignment.catalogSku,
          err,
        )
        failures.push({
          cardName: assignment.cardName,
          sellerName: assignment.sellerName,
        })
      }
    }

    setAddingToCart(false)

    // Report results via toast
    const totalAttempted = successes.length + failures.length

    if (failures.length === 0) {
      // All succeeded
      toast.success(`Added ${successes.length} cards to cart`)
      onClose()
    } else if (successes.length === 0) {
      // All failed
      toast.error(
        "Couldn't add cards to cart",
        "All items failed — please try again",
      )
    } else {
      // Partial success
      const failedNames = failures
        .map((f) => `${f.cardName} from ${f.sellerName}`)
        .join(", ")
      toast.warning(
        `Added ${successes.length}/${totalAttempted} cards`,
        `${failedNames} unavailable`,
      )
    }
  }, [result, countryCode, toast, onClose])

  const minutesSinceFetch = fetchTimestamp > 0 ? getMinutesSince(fetchTimestamp) : 0

  return (
    <Sheet open={open} onOpenChange={(o) => !o && onClose()}>
      <SheetContent
        side="right"
        data-testid="optimizer-panel"
        className="flex flex-col p-0 w-full sm:w-[420px] sm:max-w-[420px] max-h-[85vh] sm:max-h-full"
        style={{
          background: "var(--bg-base, #09090F)",
          border: "none",
          borderLeft: "1px solid var(--border-default, #2C2A4A)",
        }}
      >
        {/* Header */}
        <SheetHeader className="px-5 pt-5 pb-3">
          <SheetTitle
            className="font-barlow-condensed font-bold text-lg"
            style={{ color: "var(--text-primary, #F0EEFF)" }}
          >
            Cart Optimizer
          </SheetTitle>
          <SheetDescription
            className="text-xs"
            style={{ color: "var(--text-tertiary, #7B72A8)" }}
          >
            Find the best deals across sellers for your missing cards
          </SheetDescription>
        </SheetHeader>

        {/* Content */}
        <div className="flex-1 overflow-y-auto px-5 pb-4 space-y-4">
          {loading ? (
            <LoadingSkeleton />
          ) : result ? (
            <>
              {/* Mode toggle */}
              <OptimizerModeToggle mode={mode} onModeChange={handleModeChange} />

              {/* Staleness indicator */}
              {fetchTimestamp > 0 && (
                <div
                  data-testid="staleness-indicator"
                  className="flex items-center justify-between text-xs px-3 py-2 rounded-md"
                  style={{
                    background: isStale
                      ? "rgba(245, 158, 11, 0.1)"
                      : "var(--bg-surface-1, #18162A)",
                    color: isStale
                      ? "var(--warning, #F59E0B)"
                      : "var(--text-tertiary, #7B72A8)",
                    border: isStale
                      ? "1px solid rgba(245, 158, 11, 0.2)"
                      : "1px solid transparent",
                  }}
                >
                  <span>
                    Results from {minutesSinceFetch === 0 ? "just now" : `${minutesSinceFetch}m ago`}
                  </span>
                  {isStale && (
                    <button
                      onClick={handleRefresh}
                      data-testid="refresh-btn"
                      className="flex items-center gap-1 px-2 py-1 rounded text-xs font-medium cursor-pointer transition-colors"
                      style={{
                        background: "rgba(245, 158, 11, 0.15)",
                        color: "var(--warning, #F59E0B)",
                        border: "none",
                      }}
                    >
                      <RefreshCw style={{ width: 12, height: 12 }} />
                      Refresh
                    </button>
                  )}
                </div>
              )}

              {/* Fetch errors */}
              {fetchErrors.length > 0 && (
                <div
                  className="flex items-start gap-2 text-xs px-3 py-2 rounded-md"
                  style={{
                    background: "rgba(245, 158, 11, 0.1)",
                    color: "var(--warning, #F59E0B)",
                    border: "1px solid rgba(245, 158, 11, 0.2)",
                  }}
                >
                  <AlertTriangle style={{ width: 14, height: 14, flexShrink: 0, marginTop: 1 }} />
                  <span>
                    {fetchErrors.length} card{fetchErrors.length > 1 ? "s" : ""} had listing fetch errors
                  </span>
                </div>
              )}

              {/* Seller groups */}
              {result.sellerGroups.map((group) => (
                <SellerGroupCard
                  key={group.sellerId}
                  group={group}
                  listingsByCard={listingsByCard}
                  onOverride={handleOverride}
                />
              ))}

              {/* Unavailable cards */}
              {result.unassignedCards.length > 0 && (
                <div
                  data-testid="unavailable-cards"
                  className="rounded-lg px-4 py-3"
                  style={{
                    background: "rgba(239, 68, 68, 0.08)",
                    border: "1px solid rgba(239, 68, 68, 0.2)",
                  }}
                >
                  <div
                    className="flex items-center gap-2 mb-2"
                    style={{ color: "var(--negative, #EF4444)" }}
                  >
                    <AlertTriangle style={{ width: 14, height: 14 }} />
                    <span className="text-xs font-semibold">
                      {result.unassignedCards.length} Unavailable
                    </span>
                  </div>
                  <div className="space-y-1">
                    {result.unassignedCards.map((card) => (
                      <div
                        key={card.catalogSku}
                        className="text-xs"
                        style={{ color: "var(--text-secondary, #B8B0D8)" }}
                      >
                        {card.cardName}
                        {card.quantity > 1 && ` ×${card.quantity}`}
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </>
          ) : null}
        </div>

        {/* Footer — totals & add to cart */}
        {result && !loading && (
          <div
            className="px-5 py-4 space-y-3"
            style={{
              borderTop: "1px solid var(--border-default, #2C2A4A)",
              background: "var(--bg-surface-1, #18162A)",
            }}
          >
            {/* Cost summary */}
            <div className="space-y-1">
              <div className="flex justify-between text-xs" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
                <span>Subtotal ({result.totalCards} cards)</span>
                <span>{formatCents(result.totalCost - result.totalShipping)}</span>
              </div>
              <div className="flex justify-between text-xs" style={{ color: "var(--text-secondary, #B8B0D8)" }}>
                <span>Shipping ({result.sellerGroups.length} seller{result.sellerGroups.length !== 1 ? "s" : ""})</span>
                <span>{formatCents(result.totalShipping)}</span>
              </div>
              <div
                className="flex justify-between text-sm font-semibold pt-1"
                style={{
                  color: "var(--text-primary, #F0EEFF)",
                  borderTop: "1px solid var(--border-default, #2C2A4A)",
                }}
              >
                <span>Total</span>
                <span>{formatCents(result.totalCost)}</span>
              </div>
              {result.savings > 0 && (
                <div
                  className="flex justify-between text-xs"
                  style={{ color: "var(--positive, #10B981)" }}
                >
                  <span>You save vs buying separately</span>
                  <span>{formatCents(result.savings)}</span>
                </div>
              )}
            </div>

            {/* Add to cart button */}
            <button
              onClick={handleAddToCart}
              disabled={addingToCart || result.sellerGroups.length === 0}
              data-testid="add-to-cart-btn"
              className="w-full flex items-center justify-center gap-2 font-barlow font-semibold text-sm px-6 py-3 rounded-[10px] transition-colors text-white cursor-pointer disabled:opacity-50 disabled:cursor-default"
              style={{
                background: "var(--brand-secondary, #FF7849)",
                border: "none",
              }}
            >
              {addingToCart ? (
                <>
                  <Loader2
                    style={{ width: 16, height: 16 }}
                    className="animate-spin"
                  />
                  Adding to Cart…
                </>
              ) : (
                <>
                  <ShoppingCart style={{ width: 16, height: 16 }} />
                  Add to Cart — {formatCents(result.totalCost)}
                </>
              )}
            </button>
          </div>
        )}
      </SheetContent>
    </Sheet>
  )
}

// ─── Loading skeleton ─────────────────────────────────────────────────────────

function LoadingSkeleton() {
  return (
    <div data-testid="optimizer-loading" className="space-y-4 animate-pulse">
      {/* Mode toggle skeleton */}
      <div className="flex gap-1 rounded-lg p-1" style={{ background: "var(--bg-surface-1, #18162A)" }}>
        {[1, 2, 3].map((i) => (
          <div
            key={i}
            className="flex-1 h-9 rounded-md"
            style={{ background: "var(--bg-surface-2, #21203A)" }}
          />
        ))}
      </div>

      {/* Seller group skeletons */}
      {[1, 2].map((i) => (
        <div
          key={i}
          className="rounded-lg overflow-hidden"
          style={{ background: "var(--bg-surface-2, #21203A)" }}
        >
          <div className="px-4 py-3" style={{ borderBottom: "1px solid var(--border-default, #2C2A4A)" }}>
            <div className="h-4 w-32 rounded" style={{ background: "var(--bg-surface-1, #18162A)" }} />
          </div>
          {[1, 2, 3].map((j) => (
            <div key={j} className="px-4 py-2.5 flex justify-between">
              <div className="h-4 w-40 rounded" style={{ background: "var(--bg-surface-1, #18162A)" }} />
              <div className="h-4 w-12 rounded" style={{ background: "var(--bg-surface-1, #18162A)" }} />
            </div>
          ))}
        </div>
      ))}
    </div>
  )
}

