import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, act, within, waitFor } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import React from 'react'
import { CartOptimizerPanel } from '../CartOptimizerPanel'
import { OptimizerModeToggle } from '../OptimizerModeToggle'
import { SellerGroupCard } from '../SellerGroupCard'
import type { MissingCard, SellerGroup, OptimizationResult, OptimizerListingsResponse } from '@/lib/optimizer/types'
import type { BackendListing } from '@/types/bff'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('@/lib/data/cart', () => ({
  addToCart: vi.fn(),
}))

vi.mock('@/components/feedback/ToastProvider', () => ({
  useToast: () => ({
    success: vi.fn(),
    error: vi.fn(),
    warning: vi.fn(),
    info: vi.fn(),
  }),
}))

// Mock Sheet to simplify rendering (bypass Radix Dialog portals)
vi.mock('@/components/ui/sheet', () => ({
