// ─── Test helpers ─────────────────────────────────────────────────────────────

function makeListing(overrides: Partial<BackendListing> & { id: string; catalogSku: string; sellerId: string }): BackendListing {
  return {
    condition: 'NM',
    language: 'English',
    finish: 'nonfoil',
    price: 500, // $5.00
    currency: 'usd',
    quantity: 4,
    shippingMethod: 'standard',
    sellerName: `Seller ${overrides.sellerId}`,
    sellerType: 'consumer',
    ...overrides,
  }
}

function makeCard(sku: string, name: string, quantity = 1): MissingCard {
  return { catalogSku: sku, cardName: name, quantity }
}

function makeGroup(overrides: Partial<SellerGroup> & { sellerId: string }): SellerGroup {
  return {
    sellerName: `Seller ${overrides.sellerId}`,
    assignments: [],
    subtotal: 1000,
    shippingCost: 399,
    total: 1399,
    ...overrides,
  }
}

const defaultListingsResponse: OptimizerListingsResponse = {
  listings: {
    'SKU-A': [
      makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 500, sellerName: 'Card Kingdom' }),
      makeListing({ id: 'l2', catalogSku: 'SKU-A', sellerId: 's2', price: 600, sellerName: 'TCGPlayer' }),
    ],
    'SKU-B': [
      makeListing({ id: 'l3', catalogSku: 'SKU-B', sellerId: 's1', price: 300, sellerName: 'Card Kingdom' }),
      makeListing({ id: 'l4', catalogSku: 'SKU-B', sellerId: 's3', price: 200, sellerName: 'StarCity' }),
    ],
  },
  errors: [],
  timestamp: Date.now(),
}

const defaultCards: MissingCard[] = [
  makeCard('SKU-A', 'Lightning Bolt'),
  makeCard('SKU-B', 'Counterspell'),
]

function mockFetchSuccess(response: OptimizerListingsResponse = defaultListingsResponse) {
  return vi.fn().mockResolvedValue({
    ok: true,
    json: () => Promise.resolve(response),
  })
}

// ─── OptimizerModeToggle ──────────────────────────────────────────────────────

describe('OptimizerModeToggle', () => {
