// ─── SellerGroupCard ──────────────────────────────────────────────────────────

describe('SellerGroupCard', () => {
  const group: SellerGroup = {
    sellerId: 's1',
    sellerName: 'Card Kingdom',
    sellerRating: 95,
    sellerReviewCount: 412,
    assignments: [
      {
        catalogSku: 'SKU-A',
        cardName: 'Lightning Bolt',
        quantity: 2,
        listing: makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 500, condition: 'NM' }),
      },
      {
        catalogSku: 'SKU-B',
        cardName: 'Counterspell',
        quantity: 1,
        listing: makeListing({ id: 'l3', catalogSku: 'SKU-B', sellerId: 's1', price: 300, condition: 'LP' }),
      },
    ],
    subtotal: 1300,
    shippingCost: 399,
    total: 1699,
  }

  const listingsByCard: Record<string, BackendListing[]> = {
    'SKU-A': [
      makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 500, sellerName: 'Card Kingdom' }),
      makeListing({ id: 'l2', catalogSku: 'SKU-A', sellerId: 's2', price: 600, sellerName: 'TCGPlayer' }),
    ],
    'SKU-B': [
      makeListing({ id: 'l3', catalogSku: 'SKU-B', sellerId: 's1', price: 300, sellerName: 'Card Kingdom' }),
    ],
  }

  it('renders seller name and card count', () => {
    render(
      <SellerGroupCard group={group} listingsByCard={listingsByCard} onOverride={vi.fn()} />
    )

    expect(screen.getByText('Card Kingdom')).toBeDefined()
    expect(screen.getByText('2 cards')).toBeDefined()
  })

  it('renders card names and conditions', () => {
    render(
      <SellerGroupCard group={group} listingsByCard={listingsByCard} onOverride={vi.fn()} />
    )

    expect(screen.getByText('Lightning Bolt')).toBeDefined()
    expect(screen.getByText('Counterspell')).toBeDefined()
    expect(screen.getByText('NM')).toBeDefined()
    expect(screen.getByText('LP')).toBeDefined()
  })

  it('renders subtotal and shipping', () => {
    render(
      <SellerGroupCard group={group} listingsByCard={listingsByCard} onOverride={vi.fn()} />
    )

    expect(screen.getByText('Subtotal: $13.00')).toBeDefined()
    expect(screen.getByText('Shipping: $3.99')).toBeDefined()
    expect(screen.getByText('$16.99')).toBeDefined()
  })

  it('shows swap button for cards with alternatives', async () => {
    const user = userEvent.setup()
    render(
      <SellerGroupCard group={group} listingsByCard={listingsByCard} onOverride={vi.fn()} />
    )

    // SKU-A has alternatives (l2 from TCGPlayer), SKU-B does not
    const swapBtnA = screen.getByTestId('swap-SKU-A')
    expect(swapBtnA).toBeDefined()

    // SKU-B has no alternative sellers (only s1 in listingsByCard)
    expect(screen.queryByTestId('swap-SKU-B')).toBeNull()
  })

  it('opens swap dropdown and calls onOverride when alternative is selected', async () => {
    const user = userEvent.setup()
    const onOverride = vi.fn()
    render(
      <SellerGroupCard group={group} listingsByCard={listingsByCard} onOverride={onOverride} />
    )

    // Open swap dropdown for SKU-A
    await user.click(screen.getByTestId('swap-SKU-A'))
    expect(screen.getByTestId('swap-options-SKU-A')).toBeDefined()

    // Click the TCGPlayer alternative
    await user.click(screen.getByText('TCGPlayer'))
    expect(onOverride).toHaveBeenCalledWith('SKU-A', 'l2')
