// ─── CartOptimizerPanel ───────────────────────────────────────────────────────

describe('CartOptimizerPanel', () => {
  let originalFetch: typeof globalThis.fetch

  beforeEach(() => {
    originalFetch = globalThis.fetch
    vi.useFakeTimers({ shouldAdvanceTime: true })
  })

  afterEach(() => {
    globalThis.fetch = originalFetch
    vi.useRealTimers()
    vi.restoreAllMocks()
  })

  it('renders loading state then results after fetch', async () => {
    globalThis.fetch = mockFetchSuccess()

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    // After fetch completes, should show mode toggle and results
    await waitFor(() => {
      expect(screen.getByTestId('mode-toggle')).toBeDefined()
    })

    // Should have seller groups
    expect(screen.getByTestId('add-to-cart-btn')).toBeDefined()
  })

  it('mode toggle switches optimization results without re-fetching', async () => {
    const fetchMock = mockFetchSuccess()
    globalThis.fetch = fetchMock

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('mode-toggle')).toBeDefined()
    })

    // Initial fetch = 1 call
    const initialCallCount = fetchMock.mock.calls.length

    // Switch mode
    const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime })
    await user.click(screen.getByTestId('mode-cheapest'))

    // Should NOT have called fetch again
    expect(fetchMock.mock.calls.length).toBe(initialCallCount)
  })

  it('seller groups render with correct card count and totals', async () => {
    globalThis.fetch = mockFetchSuccess()

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('add-to-cart-btn')).toBeDefined()
    })

    // Should render the total cost in the add-to-cart button
    const btn = screen.getByTestId('add-to-cart-btn')
    expect(btn.textContent).toContain('Add to Cart')
    expect(btn.textContent).toContain('$')
  })

  it('unavailable cards section renders when some cards have no listings', async () => {
    const responseWithUnavailable: OptimizerListingsResponse = {
      listings: {
        'SKU-A': [
          makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 500 }),
        ],
        // SKU-B has no listings — card will be unassigned
      },
      errors: [],
      timestamp: Date.now(),
    }

    globalThis.fetch = mockFetchSuccess(responseWithUnavailable)

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('unavailable-cards')).toBeDefined()
    })

    expect(screen.getByText('Counterspell')).toBeDefined()
  })

  it('per-card override replaces seller and updates totals', async () => {
    // Create listings where SKU-A has two sellers with different prices
    const response: OptimizerListingsResponse = {
      listings: {
        'SKU-A': [
          makeListing({ id: 'l1', catalogSku: 'SKU-A', sellerId: 's1', price: 500, sellerName: 'Cheap Shop' }),
          makeListing({ id: 'l2', catalogSku: 'SKU-A', sellerId: 's2', price: 900, sellerName: 'Pricey Store' }),
        ],
      },
      errors: [],
      timestamp: Date.now(),
    }

    globalThis.fetch = mockFetchSuccess(response)

    const cards = [makeCard('SKU-A', 'Lightning Bolt')]

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={cards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('mode-toggle')).toBeDefined()
    })

    // Should have assigned to cheap seller initially
    // The swap button should exist for SKU-A
    const swapBtn = screen.queryByTestId('swap-SKU-A')
    if (swapBtn) {
      const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime })
      await user.click(swapBtn)

      // Should show Pricey Store as alternative
      await waitFor(() => {
        expect(screen.getByTestId('swap-options-SKU-A')).toBeDefined()
      })
    }
  })

  it('add-to-cart calls addToCart for each selected listing', async () => {
    const { addToCart } = await import('@/lib/data/cart')
    const addToCartMock = vi.mocked(addToCart)
    addToCartMock.mockResolvedValue(undefined)

    // Mock fetch for both listings fetch and product lookup
    let callIndex = 0
    globalThis.fetch = vi.fn().mockImplementation((url: string) => {
      if (typeof url === 'string' && url.includes('/api/optimizer/listings')) {
        return Promise.resolve({
          ok: true,
          json: () => Promise.resolve(defaultListingsResponse),
        })
      }
      // Product lookup
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve({
          products: [{ variants: [{ id: `var-${callIndex++}` }] }],
        }),
      })
    })

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('add-to-cart-btn')).toBeDefined()
    })

    const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime })
    await user.click(screen.getByTestId('add-to-cart-btn'))

    // Give time for sequential add-to-cart calls
    await waitFor(() => {
      expect(addToCartMock).toHaveBeenCalled()
    })
  })

  it('partial failure shows warning with failed card names', async () => {
    const { addToCart } = await import('@/lib/data/cart')
    const { useToast } = await import('@/components/feedback/ToastProvider')
    const toastMock = useToast()
    const warningMock = vi.mocked(toastMock.warning)

    const addToCartMock = vi.mocked(addToCart)
    let callCount = 0
    addToCartMock.mockImplementation(async () => {
      callCount++
      if (callCount === 2) throw new Error('Out of stock')
    })

    globalThis.fetch = vi.fn().mockImplementation((url: string) => {
      if (typeof url === 'string' && url.includes('/api/optimizer/listings')) {
        return Promise.resolve({
          ok: true,
          json: () => Promise.resolve(defaultListingsResponse),
        })
      }
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve({
          products: [{ variants: [{ id: `var-${callCount}` }] }],
        }),
      })
    })

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('add-to-cart-btn')).toBeDefined()
    })

    const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime })
    await user.click(screen.getByTestId('add-to-cart-btn'))

    await waitFor(() => {
      expect(warningMock).toHaveBeenCalled()
    })
  })

  it('staleness: results older than 5 min show refresh button', async () => {
    const staleResponse: OptimizerListingsResponse = {
      ...defaultListingsResponse,
      timestamp: Date.now() - 6 * 60 * 1000, // 6 min ago
    }

    globalThis.fetch = mockFetchSuccess(staleResponse)

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={vi.fn()}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('staleness-indicator')).toBeDefined()
    })

    // Should show refresh button
    expect(screen.getByTestId('refresh-btn')).toBeDefined()
  })

  it('panel closes on full add-to-cart success', async () => {
    const { addToCart } = await import('@/lib/data/cart')
    const addToCartMock = vi.mocked(addToCart)
    addToCartMock.mockResolvedValue(undefined)

    const onClose = vi.fn()

    globalThis.fetch = vi.fn().mockImplementation((url: string) => {
      if (typeof url === 'string' && url.includes('/api/optimizer/listings')) {
        return Promise.resolve({
          ok: true,
          json: () => Promise.resolve(defaultListingsResponse),
        })
      }
      return Promise.resolve({
        ok: true,
        json: () => Promise.resolve({
          products: [{ variants: [{ id: 'var-1' }] }],
        }),
      })
    })

    await act(async () => {
      render(
        <CartOptimizerPanel
          missingCards={defaultCards}
          open={true}
          onClose={onClose}
        />
      )
    })

    await waitFor(() => {
      expect(screen.getByTestId('add-to-cart-btn')).toBeDefined()
    })

    const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime })
    await user.click(screen.getByTestId('add-to-cart-btn'))

    await waitFor(() => {
      expect(onClose).toHaveBeenCalled()
    })
  })
})

// ─── Voltage compliance ───────────────────────────────────────────────────────

describe('Voltage compliance', () => {
  it('no bare Tailwind color classes in optimizer component files', async () => {
    const fs = await import('fs')
    const path = await import('path')

    const optimizerDir = path.resolve(__dirname, '..')
    const files = fs.readdirSync(optimizerDir).filter((f: string) => f.endsWith('.tsx'))

    const bareColorPattern = /\b(bg-white|bg-gray-|text-gray-|border-gray-)/g

    for (const file of files) {
      const content = fs.readFileSync(path.join(optimizerDir, file), 'utf-8')
      const matches = content.match(bareColorPattern)
      expect(
        matches,
        `${file} contains bare Tailwind color classes: ${matches?.join(', ')}`
      ).toBeNull()
    }
  })
})

